	private List<String> rows(String query) {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn.prepareTupleQuery(query).evaluate());
			return serializedRows(result);
		}
	}

	private static List<String> serializedRows(List<BindingSet> result) {
		return result.stream()
				.map(bs -> bs.getBindingNames()
						.stream()
						.sorted()
						.map(name -> name + "=" + bs.getValue(name))
						.collect(Collectors.joining(";", "[", "]")))
				.sorted()
				.collect(Collectors.toList());
	}

	private List<String> rowsWithProperty(String property, String value, String query) {
		String previous = System.getProperty(property);
		try {
			System.setProperty(property, value);
			return rows(query);
		} finally {
			if (previous == null) {
				System.clearProperty(property);
			} else {
				System.setProperty(property, previous);
			}
		}
	}

	private List<String> rowsWithProperties(String query, String... propertyValuePairs) {
		assertThat(propertyValuePairs.length).isEven();
		String[] previous = new String[propertyValuePairs.length / 2];
		try {
			for (int i = 0; i < propertyValuePairs.length; i += 2) {
				previous[i / 2] = System.getProperty(propertyValuePairs[i]);
				System.setProperty(propertyValuePairs[i], propertyValuePairs[i + 1]);
			}
			return rows(query);
		} finally {
			for (int i = propertyValuePairs.length - 2; i >= 0; i -= 2) {
				if (previous[i / 2] == null) {
					System.clearProperty(propertyValuePairs[i]);
				} else {
					System.setProperty(propertyValuePairs[i], previous[i / 2]);
				}
			}
		}
	}

