	@Test
	public void externalRootChunkRefillDoesNotConstrainAggregateRows() {
		// One full morsel per worker plus one row guarantees that some worker refills its external-root batch.
		int roots = LmdbNativeChunkPipeline.BATCH_ROWS * LmdbNativeParallelPipelines.configuredThreads() + 1;
		try (SailRepositoryConnection connection = repository.getConnection()) {
			ValueFactory vf = connection.getValueFactory();
			IRI rootPredicate = vf.createIRI(EX, "refillAggregateRoot");
			IRI valuePredicate = vf.createIRI(EX, "refillAggregateValue");
			IRI tailPredicate = vf.createIRI(EX, "refillAggregateTail");
			connection.begin();
			for (int i = 0; i < roots; i++) {
				IRI subject = vf.createIRI(EX, "refillAggregate/subject/" + i);
				IRI middle = vf.createIRI(EX, "refillAggregate/middle/" + i);
				IRI value = vf.createIRI(EX, "refillAggregate/value/" + i);
				connection.add(subject, rootPredicate, middle);
				connection.add(middle, valuePredicate, value);
				connection.add(value, tailPredicate, vf.createIRI(EX, "refillAggregate/tail/" + i));
			}
			connection.commit();
		}

		String query = "PREFIX ex: <" + EX + ">\n"
				+ "SELECT ?subject (COUNT(?leaf) AS ?count) (MIN(DISTINCT ?leaf) AS ?min) WHERE {\n"
				+ "  ?subject ex:refillAggregateRoot ?middle .\n"
				+ "  ?middle ex:refillAggregateValue ?value .\n"
				+ "  ?value ex:refillAggregateTail ?leaf .\n"
				+ "} GROUP BY ?subject";
		long parallelBefore = LmdbNativeParallelAggregation.PARALLEL_RUNS.get();
		long chunkBefore = LmdbNativeChunkPipeline.ENGAGED.get();

		List<String> parallel = rows(query);

		assertThat(LmdbNativeParallelAggregation.PARALLEL_RUNS.get())
				.as("the refill regression must exercise parallel aggregation")
				.isEqualTo(parallelBefore + 1L);
		assertThat(LmdbNativeChunkPipeline.ENGAGED.get())
				.as("the aggregate prefix must cross an external-root chunk refill")
				.isGreaterThan(chunkBefore);
		assertThat(parallel)
				.as("stale ?value bindings must not remove groups after the first worker batch")
				.hasSize(roots)
				.containsExactlyElementsOf(rowsWithProperty(NATIVE_FLAG, "false", query));
	}

