	@Test
	public void floatingAggregateFallsBackWithoutClaimingParallelRun() {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI predicate = vf.createIRI(EX, "floatingValue");
			conn.add(vf.createIRI(EX, "floating/1"), predicate, vf.createLiteral(1));
			conn.add(vf.createIRI(EX, "floating/2"), predicate, vf.createLiteral(2));
			conn.add(vf.createIRI(EX, "floating/late"), predicate, vf.createLiteral(0.1d));
		}
		String query = "PREFIX ex: <" + EX + ">\n"
				+ "SELECT (COUNT(*) AS ?count) (SUM(?v) AS ?sum) (AVG(?v) AS ?avg) "
				+ "WHERE { ?s ex:floatingValue ?v }";

		long before = LmdbNativeParallelAggregation.PARALLEL_RUNS.get();
		List<String> actual = rows(query);
		assertThat(actual).isEqualTo(rowsWithProperty(PARALLEL_FLAG, "false", query));
		assertThat(actual).isEqualTo(rowsWithProperty(NATIVE_FLAG, "false", query));
		assertThat(strategy(query)).isEqualTo("aggState");
		assertThat(LmdbNativeParallelAggregation.PARALLEL_RUNS.get())
				.as("an aborted floating-point attempt must not claim a successful parallel run")
				.isEqualTo(before);

		String exactQuery = starWithValues(
				"(COUNT(*) AS ?count) (SUM(?v) AS ?sum) (AVG(?v) AS ?avg) (MIN(DISTINCT ?v) AS ?min)");
		long exactBefore = LmdbNativeParallelAggregation.PARALLEL_RUNS.get();
		assertAllThreeAgree(exactQuery);
		assertThat(LmdbNativeParallelAggregation.PARALLEL_RUNS.get())
				.as("a fallback must not disable a subsequent exact integer/decimal parallel query")
				.isGreaterThan(exactBefore);
	}

	@Test
	public void unmarkedFunctionRunsOnceWhenLateFloatingSumFallsBack() {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			ValueFactory vf = connection.getValueFactory();
			IRI predicate = vf.createIRI(EX, "replayMatch");
			IRI matched = vf.createIRI(EX, "matched");
			for (int i = 1; i <= 6; i++) {
				connection.add(vf.createIRI(EX, "replayRow" + i), predicate, matched);
			}
		}
		String query = "PREFIX ex: <" + EX + ">\n"
				+ "PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>\n"
				+ "SELECT (COUNT(*) AS ?count) (SUM(?v) AS ?sum) WHERE {\n"
				+ "  {\n"
				+ "    VALUES (?row ?v) {\n"
				+ "      (ex:replayRow1 10) (ex:replayRow2 20)\n"
				+ "      (ex:replayRow3 30) (ex:replayRow4 40)\n"
				+ "      (ex:replayRow5 \"1.0\"^^xsd:double)\n"
				+ "      (ex:replayRow6 \"0.1\"^^xsd:double)\n"
				+ "    }\n"
				+ "    FILTER(<" + COUNTING_TRUE_FUNCTION + ">(?row))\n"
				+ "  }\n"
				+ "  ?row ex:replayMatch ex:matched .\n"
				+ "}";

		CountingTrueFunction function = new CountingTrueFunction();
		FunctionRegistry registry = FunctionRegistry.getInstance();
		registry.add(function);
		try {
			SpeculativeCounters before = SpeculativeCounters.snapshot();
			List<BindingSet> result;
			try (SailRepositoryConnection connection = repository.getConnection()) {
				result = QueryResults.asList(connection.prepareTupleQuery(query).evaluate());
			}
			assertThat(function.calls())
					.as("an encounter-order fallback must not replay an unmarked function")
					.isEqualTo(6);
			assertThat(SpeculativeCounters.snapshot())
					.as("an unsafe plan must publish no speculative strategy counters")
					.isEqualTo(before);
			assertThat(result).singleElement().satisfies(row -> {
				assertThat(((Literal) row.getValue("count")).longValue()).isEqualTo(6L);
				Literal sum = (Literal) row.getValue("sum");
				assertThat(sum.getCoreDatatype()).isEqualTo(CoreDatatype.XSD.DOUBLE);
				assertThat(sum.getLabel()).isEqualTo("101.1");
			});
			List<String> actual = serializedRows(result);
			function.reset();
			assertThat(actual).isEqualTo(rowsWithProperty(NATIVE_FLAG, "false", query));
			assertThat(function.calls()).as("generic evaluation calls at the original row boundary").isEqualTo(6);
			function.reset();
			assertThat(strategy(query)).isEqualTo("aggState");
			assertThat(function.calls()).as("telemetry evaluation also stays sequential").isEqualTo(6);
			assertThat(SpeculativeCounters.snapshot()).isEqualTo(before);
		} finally {
			registry.remove(function);
		}
	}

	@Test
	public void catastrophicCancellationSumUsesSequentialEncounterOrder() {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI predicate = vf.createIRI(EX, "cancellationMatch");
			IRI first = vf.createIRI(EX, "cancellationFirst");
			IRI second = vf.createIRI(EX, "cancellationSecond");
			IRI third = vf.createIRI(EX, "cancellationThird");
			conn.add(first, predicate, vf.createIRI(EX, "cancellation/match/first/1"));
			conn.add(second, predicate, vf.createIRI(EX, "cancellation/match/second/1"));
			conn.add(second, predicate, vf.createIRI(EX, "cancellation/match/second/2"));
			conn.add(third, predicate, vf.createIRI(EX, "cancellation/match/third/1"));
			conn.add(third, predicate, vf.createIRI(EX, "cancellation/match/third/2"));
		}
		// VALUES is the native compiler's deterministic prefix cursor here. The branch expands its three rows with
		// multiplicities 1, 2, and 2, so the ordinary left fold is
		// 1e16, -1e16, -1e16, 1, 1 -> -1e16. Multiplying each prefix value by its factorized weight would instead
		// produce -9.999999999999998e15, making reassociation observable without assuming an LMDB index scan order.
		String query = "PREFIX ex: <" + EX + ">\n"
				+ "SELECT (SUM(?v) AS ?sum) WHERE {\n"
				+ "  VALUES (?s ?v) {\n"
				+ "    (ex:cancellationFirst 1.0e16)\n"
				+ "    (ex:cancellationSecond -1.0e16)\n"
				+ "    (ex:cancellationThird 1.0)\n"
				+ "  }\n"
				+ "  ?s ex:cancellationMatch ?match .\n"
				+ "}";

		long before = LmdbNativeParallelAggregation.PARALLEL_RUNS.get();
		long factorizedBefore = FactorizedTail.ENGAGED.get();
		List<String> actual = rows(query);
		assertThat(actual).isEqualTo(rowsWithProperty(PARALLEL_FLAG, "false", query));
		assertThat(actual).isEqualTo(rowsWithProperty(NATIVE_FLAG, "false", query));
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn.prepareTupleQuery(query).evaluate());
			assertThat(result).singleElement().satisfies(row -> {
				Literal sum = (Literal) row.getValue("sum");
				assertThat(sum.getCoreDatatype()).isEqualTo(CoreDatatype.XSD.DOUBLE);
				assertThat(sum.getLabel()).isEqualTo("-1.0E16");
			});
		}
		assertThat(strategy(query)).isEqualTo("aggState");
		assertThat(LmdbNativeParallelAggregation.PARALLEL_RUNS.get())
				.as("floating cancellation must use the original sequential left fold")
				.isEqualTo(before);
		assertThat(FactorizedTail.ENGAGED.get())
				.as("an aborted weighted floating attempt must not claim factorized engagement")
				.isEqualTo(factorizedBefore);

		String exactControl = "PREFIX ex: <" + EX + ">\n"
				+ "SELECT (SUM(?v) AS ?sum) WHERE {\n"
				+ "  VALUES (?s ?v) {\n"
				+ "    (ex:cancellationFirst 10)\n"
				+ "    (ex:cancellationSecond -10)\n"
				+ "    (ex:cancellationThird 1)\n"
				+ "  }\n"
				+ "  ?s ex:cancellationMatch ?match .\n"
				+ "}";
		long exactFactorizedBefore = FactorizedTail.ENGAGED.get();
		assertThat(strategy(exactControl)).startsWith("factorizedTail(");
		assertThat(FactorizedTail.ENGAGED.get())
				.as("the same repeatable exact shape must still commit factorized engagement")
				.isGreaterThan(exactFactorizedBefore);
	}

