	@Test
	public void unmarkedFunctionRunsOnceWhenExtremaTieFallsBack() {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			ValueFactory vf = connection.getValueFactory();
			IRI predicate = vf.createIRI(EX, "replayExtreme");
			connection.add(vf.createIRI(EX, "extreme/first"), predicate, vf.createLiteral(1));
			connection.add(vf.createIRI(EX, "extreme/second"), predicate,
					vf.createLiteral("1.0", CoreDatatype.XSD.DECIMAL));
		}
		String query = "PREFIX ex: <" + EX + ">\n"
				+ "SELECT (COUNT(DISTINCT ?v) AS ?count) (MIN(?v) AS ?min) (MAX(?v) AS ?max) WHERE {\n"
				+ "  ?row ex:replayExtreme ?v .\n"
				+ "  FILTER(<" + COUNTING_TRUE_FUNCTION + ">(?row))\n"
				+ "}";

		CountingTrueFunction function = new CountingTrueFunction();
		FunctionRegistry registry = FunctionRegistry.getInstance();
		registry.add(function);
		try {
			SpeculativeCounters before = SpeculativeCounters.snapshot();
			List<BindingSet> result;
			try (SailRepositoryConnection connection = repository.getConnection()) {
				result = QueryResults.asList(connection.prepareTupleQuery(query).evaluate());
			}
			assertThat(function.calls())
					.as("an extrema representative fallback must not replay an unmarked function")
					.isEqualTo(2);
			assertThat(SpeculativeCounters.snapshot())
					.as("an unsafe ordered-DISTINCT plan must publish no speculative counters")
					.isEqualTo(before);
			assertThat(result).singleElement().satisfies(row -> {
				assertThat(((Literal) row.getValue("count")).longValue()).isEqualTo(2L);
				// Ordered-v1 POSC encounters the decimal id first; fallback must preserve that exact
				// comparator-equal RDF term while avoiding a replay of the unmarked function.
				Literal min = (Literal) row.getValue("min");
				Literal max = (Literal) row.getValue("max");
				assertThat(min.getCoreDatatype()).isEqualTo(CoreDatatype.XSD.DECIMAL);
				assertThat(min.getLabel()).isEqualTo("1.0");
				assertThat(max.getCoreDatatype()).isEqualTo(CoreDatatype.XSD.DECIMAL);
				assertThat(max.getLabel()).isEqualTo("1.0");
			});
			List<String> actual = serializedRows(result);
			function.reset();
			assertThat(actual).isEqualTo(rowsWithProperty(NATIVE_FLAG, "false", query));
			assertThat(function.calls()).as("generic evaluation calls once per source row").isEqualTo(2);
			function.reset();
			assertThat(strategy(query)).isEqualTo("aggState");
			assertThat(function.calls()).as("telemetry evaluation also stays sequential").isEqualTo(2);
			assertThat(SpeculativeCounters.snapshot()).isEqualTo(before);
		} finally {
			registry.remove(function);
		}
	}

